use criterion::{BenchmarkId, Criterion, black_box, criterion_group, criterion_main};
use exlex::Exlex;

#[path = "common/mod.rs"]
mod common;

fn bench_asymptotic(c: &mut Criterion) {
    let mut group = c.benchmark_group("Asymptotic_Crossover");

    // Loop through the exact same scales generated by gen_fixtures.rs
    for count in (5..=100).step_by(5) {
        let fixture_name = format!("scale_{:03}", count);

        let exlex_str = common::loader::load_fixture(&fixture_name, "exlex");
        let json_str = common::loader::load_fixture(&fixture_name, "json");

        let exlex_parsed = Exlex::init_reader(&exlex_str, None, None, None, None).unwrap();
        let json_parsed: serde_json::Value = serde_json::from_str(&json_str).unwrap();

        let target_section = format!("scale_{}", count);
        let target_sect_id = exlex_parsed
            .get_child(&target_section, exlex_parsed.get_root())
            .unwrap();

        // Always target the absolute last key to force Exlex to scan the whole array
        let worst_case_key = format!("key_{}", count - 1);

        group.bench_with_input(BenchmarkId::new("Exlex", count), &count, |b, _| {
            b.iter(|| {
                let val = exlex_parsed
                    .get_property(black_box(&worst_case_key), black_box(target_sect_id))
                    .unwrap();
                black_box(val);
            })
        });

        group.bench_with_input(BenchmarkId::new("Serde JSON", count), &count, |b, _| {
            b.iter(|| {
                let val = json_parsed[&target_section]
                    .get(black_box(&worst_case_key))
                    .unwrap()
                    .as_str()
                    .unwrap();
                black_box(val);
            })
        });
    }

    group.finish();
}

criterion_group!(benches, bench_asymptotic);
criterion_main!(benches);
